/**
 * Projects future operational complexity and fragility for a workflow definition
using deterministic statistical methods applied to historical governance rollup data.

Projection methods (selected automatically based on data availability):
  • no_data                   - no rollup history; returns structural baseline
  • last_known_value          - 1 data point; no extrapolation
  • weighted_moving_average   - 2-6 data points; triangular-weighted slope
  • weighted_linear_regression - ≥ 7 data points; full WLS slope extrapolation

Confidence levels:
  • low      - fewer than 7 data points, or high volatility, or window > 14 days
  • moderate - 7-13 data points (before volatility/window penalties)
  • high     - ≥ 14 data points with low volatility and window ≤ 14 days

Trend directions: improving | stable | degrading | critically_degrading

READ-ONLY - never mutates governance history, triggers alerts, or invokes execution.
Assistive deterministic forecasting only - no autonomous actions, no ML.

 * @summary Deterministic operational trend forecast for a workflow (P8-D)
 */
export const getGetWorkflowForecastUrl = (
  id: number,
  params?: GetWorkflowForecastParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/workflows/${id}/forecast?${stringifiedParams}`
    : `/api/workflows/${id}/forecast`;
};

